package com.jucheonsu.port.domain.project.controller;
import com.jucheonsu.port.domain.project.dto.request.*;import com.jucheonsu.port.domain.project.dto.response.ProjectResponse;import com.jucheonsu.port.domain.project.service.ProjectService;import com.jucheonsu.port.global.response.ApiResponse;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController@RequestMapping("/api/portfolios/{portfolioId}/projects")@RequiredArgsConstructor public class ProjectController{private final ProjectService service;@GetMapping public ApiResponse<List<ProjectResponse>> get(@PathVariable Long portfolioId){return ApiResponse.ok(service.getProjects(portfolioId));}@PostMapping public ApiResponse<ProjectResponse> create(@PathVariable Long portfolioId,@Valid @RequestBody ProjectCreateRequest r){return ApiResponse.ok(service.create(portfolioId,r));}@PutMapping("/{projectId}") public ApiResponse<ProjectResponse> update(@PathVariable Long portfolioId,@PathVariable Long projectId,@Valid @RequestBody ProjectUpdateRequest r){return ApiResponse.ok(service.update(portfolioId,projectId,r));}@DeleteMapping("/{projectId}") public ApiResponse<Void> delete(@PathVariable Long portfolioId,@PathVariable Long projectId){service.delete(portfolioId,projectId);return ApiResponse.ok();}@PutMapping("/order") public ApiResponse<Void> order(@PathVariable Long portfolioId,@RequestBody List<ProjectOrderRequest> r){service.updateOrders(portfolioId,r);return ApiResponse.ok();}}
